for stage in 1 2 3; do
  case $stage in
    1) name="BASE (merge-base — common ancestor)";;
    2) name="OURS/HEAD (origin reslate, already on new base)";;
    3) name="THEIRS/incoming (our commit 2cdc097c1)";;
  esac
  echo "===== stage $stage : $name ====="
  jq -r '.jjgg_heats["₣BY"].jjghn_paces["₢BYAAA"].jjgpn_tacks[] | "ts=\(.jjgtn_ts)  state=\(.jjgtn_state)  basis=\(.jjgtn_basis)  silks=\(.jjgtn_silks)"' /tmp/gallops-stage$stage.json 2>&1
  echo
done

for stage in 1 2 3; do
  case $stage in
    1) name="BASE  (merge-base b1d2a9ae4 — common ancestor)";;
    2) name="OURS/HEAD  (origin's reslate, already rebuilt on new base)";;
    3) name="THEIRS/incoming  (our commit 2cdc097c1 being replayed)";;
  esac
  echo "===== stage $stage : $name ====="
  jq -r '.jjgrn_heats["₣BY"].jjghn_paces["₢BYAAA"].jjgpn_tacks[] | "  ts=\(.jjgtn_ts)  state=\(.jjgtn_state)  basis=\(.jjgtn_basis)  silks=\(.jjgtn_silks)"' /tmp/gallops-stage$stage.json 2>&1
