ssh cerebro 'R=$(ls -d ~/projects/rbm_alpha* 2>/dev/null | head -1);
echo "==== REPO PATH: $R";
echo "==== bare? ===="; git -C "$R" rev-parse --is-bare-repository;
echo "==== current branch / HEAD ===="; git -C "$R" rev-parse --abbrev-ref HEAD; git -C "$R" rev-parse HEAD;
echo "==== status (short) ===="; git -C "$R" status -sb;
echo "==== uncommitted diffstat (tracked) ===="; git -C "$R" diff --stat; 
echo "==== staged diffstat ===="; git -C "$R" diff --cached --stat;
echo "==== untracked count ===="; git -C "$R" ls-files --others --exclude-standard | wc -l;
echo "==== branches -vv ===="; git -C "$R" branch -vv;
echo "==== remotes ===="; git -C "$R" remote -v;
echo "==== receive.denyCurrentBranch ===="; git -C "$R" config --get receive.denyCurrentBranch || echo "(unset -> default refuse)";
echo "==== recent log -12 ===="; git -C "$R" log --oneline -12;
echo "(end)"' 2>&1

ssh cerebro 'R=/home/bhyslop/projects/rbm_alpha_recipemuster;
echo "==== cerebro main vs origin/main: the 3 ahead commits, files touched ====";
git -C "$R" diff --stat 98c5ca478..main;
echo;
echo "==== can cerebro fast-forward push these to origin/main? (ahead N / behind M) ====";
git -C "$R" rev-list --left-right --count origin/main...main | awk "{print \"behind origin: \"\$1\"   ahead origin: \"\$2}";
echo;
echo "==== does cerebro origin/main match the github tip we know (98c5ca478)? ====";
git -C "$R" rev-parse --short origin/main' 2>&1
